import { collection, getDocs, addDoc, deleteDoc, doc, updateDoc } from "firebase/firestore";
import { db } from "../firebase";

// Fetch all policies
export const getPolicies = async () => {
  try {
    const querySnapshot = await getDocs(collection(db, "knowledge_base"));
    const policies = [];
    querySnapshot.forEach((doc) => {
      policies.push({ id: doc.id, ...doc.data() });
    });
    return policies;
  } catch (error) {
    console.error("Error fetching policies:", error);
    return [];
  }
};

// Add a new policy
export const addPolicy = async (title, content, category) => {
  try {
    await addDoc(collection(db, "knowledge_base"), {
      title,
      content,
      category,
      createdAt: new Date()
    });
    return true;
  } catch (error) {
    console.error("Error adding policy:", error);
    return false;
  }
};

// Update a policy
export const updatePolicy = async (id, title, content, category) => {
  try {
    await updateDoc(doc(db, "knowledge_base", id), {
      title,
      content,
      category
    });
    return true;
  } catch (error) {
    console.error("Error updating policy:", error);
    return false;
  }
};

// Delete a policy
export const deletePolicy = async (id) => {
  try {
    await deleteDoc(doc(db, "knowledge_base", id));
    return true;
  } catch (error) {
    console.error("Error deleting policy:", error);
    return false;
  }
};
